#include "EPD.h"
#include "GUI_Paint.h"

#include <esp_now.h>
#include <WiFi.h>

#define SCREEN_W 400
#define SCREEN_H 300
#define REFRESH_INTERVAL_MIN 2   // refresh every 3 minutes

UBYTE *BlackImage, *RYImage;

float latestTemperature = -100.0;
unsigned long lastUpdateTime = 0;
unsigned long refreshInterval = REFRESH_INTERVAL_MIN * 60 * 1000UL;

// ------------------------------------
// ESP-NOW Data Structure
typedef struct struct_message {
  float temperature;
} struct_message;

struct_message incomingData;
// ------------------------------------

// ======== DATA RECEIVED CALLBACK ========
void onReceive(const uint8_t * mac, const uint8_t *incomingDataBytes, int len) {
  memcpy(&incomingData, incomingDataBytes, sizeof(incomingData));
  latestTemperature = incomingData.temperature;
  Serial.print("ESP-NOW Received: ");
  Serial.println(latestTemperature);
}

// ======== SETUP ========
void setup() {
  USBSerial.begin(115200);
  USBSerial.println("ESP32-S3 E-Ink ESP-NOW Receiver Starting...");

  DEV_Module_Init();
  eink_init();

 WiFi.mode(WIFI_STA);
   USBSerial.println("MAC Address: ");
  USBSerial.println(WiFi.macAddress());   ////// 3C:84:27:C0:E8:BC

  WiFi.disconnect();

  if (esp_now_init() != ESP_OK) {
    USBSerial.println("ESP-NOW Init Failed!");
    return;
  }

  esp_now_register_recv_cb(onReceive);

  displayText("Waiting for ESP-NOW...");
  lastUpdateTime = millis();
}

// ======== LOOP ========
void loop() {

  // Update screen every 3 minutes
  if (millis() - lastUpdateTime >= refreshInterval) {
    updateDisplay(latestTemperature);
    lastUpdateTime = millis();
  }
}

// ======== E-INK INITIALIZATION ========
void eink_init() {
  USBSerial.println("E-Ink Init...");
  EPD_4IN2B_V2_Init();
  EPD_4IN2B_V2_Clear();
  delay(500);

  long Imagesize = SCREEN_W * SCREEN_H / 8;
  BlackImage = (UBYTE *)malloc(Imagesize);
  RYImage = (UBYTE *)malloc(Imagesize);

  Paint_NewImage(BlackImage, SCREEN_W, SCREEN_H, 0, WHITE);
  Paint_NewImage(RYImage, SCREEN_W, SCREEN_H, 0, WHITE);
}

// ======== DISPLAY TEXT FUNCTION ========
void displayText(String message) {
  Paint_SelectImage(BlackImage);
  Paint_Clear(WHITE);
  Paint_SelectImage(RYImage);
  Paint_Clear(WHITE);

  Paint_SelectImage(RYImage);
  Paint_DrawString_EN(45, 80, "ESP32S3 RECEIVER", &Font24, WHITE, RED);

  Paint_SelectImage(BlackImage);
  Paint_DrawString_EN(50, 150, message.c_str(), &Font24, BLACK, WHITE);

  EPD_4IN2B_V2_Display(BlackImage, RYImage);
  delay(2000);
}

