void updateDisplay(float temp) {
  char msg[64];
  if (temp < -50) {
    sprintf(msg, "No Data");
  } else {
    sprintf(msg, "Temp: %.2f C", temp);
  }

  EPD_4IN2B_V2_Init();
  displayText(String(msg));
  EPD_4IN2B_V2_Sleep();
